     1→#!/usr/bin/env node
     2→/**
     3→ * End-to-End Testing CLI Tool (T036k)
     4→ *
     5→ * Simple CLI for manual end-to-end testing of classification pipeline.
     6→ * Supports single email, batch, and date-range processing modes.
     7→ *
     8→ * Usage:
     9→ *   npm run test:pipeline -- --mode single --message-id <id>
    10→ *   npm run test:pipeline -- --mode batch --limit 10
    11→ *   npm run test:pipeline -- --mode date-range --start 2025-09-01 --end 2025-09-30 --limit 50
    12→ *   npm run test:pipeline -- --dry-run  # Classify without persisting
    13→ *
    14→ * Output:
    15→ *   - Per-email: [message_id] subject → labels: [label1, label2] (confidence: 0.85) - 8.3s
    16→ *   - Summary: Processed 10 emails in 83.5s (avg 8.35s/email), 9 success, 1 error
    17→ *   - Explainability traces: ./test-pipeline-results/<timestamp>/<message_id>.json
    18→ */
    19→
    20→import { promises as fs } from 'fs';
    21→import { join, dirname } from 'path';
    22→import {
    23→  fetchEmailById,
    24→  fetchUnclassifiedEmails,
    25→  fetchEmailsByDateRange,
    26→  closePool as closeQueryPool,
    27→} from '../persistence/email-query';
    28→import { saveClassificationResult, closePool as closeWriterPool } from '../persistence/classification-writer';
    29→import {
    30→  ClassificationPipeline,
    31→  ConfigurationLoader,
    32→  type CategoryConfiguration,
    33→  type EmailMessage,
    34→  type ClassificationResult,
    35→  type SelectedLabel,
    36→} from '@gmail-automation/classification-engine';
    37→
    38→/**
    39→ * CLI argument structure
    40→ */
    41→export interface CLIArguments {
    42→  mode: 'single' | 'batch' | 'date-range' | 'replay' | 'replay-from';
    43→  messageId?: string;
    44→  limit?: number;
    45→  startDate?: string;
    46→  endDate?: string;
    47→  dryRun: boolean;
    48→  replayFrom?: string;
    49→  sessionId?: string;
    50→}
    51→
    52→/**
    53→ * Processing summary statistics
    54→ */
    55→export interface ProcessingSummary {
    56→  totalEmails: number;
    57→  success: number;
    58→  errors: number;
    59→  totalDurationMs: number;
    60→  errorDetails: Array<{ messageId: string; error: string }>;
    61→}
    62→
    63→/**
    64→ * Find the monorepo root directory by searching upward for package.json with workspaces
    65→ *
    66→ * @param startDir - Directory to start searching from (defaults to current working directory)
    67→ * @returns Path to monorepo root directory
    68→ * @throws Error if monorepo root cannot be found
    69→ */
    70→export async function findRepoRoot(startDir: string = process.cwd()): Promise<string> {
    71→  let currentDir = startDir;
    72→  const root = '/';
    73→
    74→  while (currentDir !== root) {
    75→    try {
    76→      const packageJsonPath = join(currentDir, 'package.json');
    77→      const packageJsonContent = await fs.readFile(packageJsonPath, 'utf-8');
    78→      const packageJson = JSON.parse(packageJsonContent);
    79→
    80→      // Check if this package.json has workspaces field (indicates monorepo root)
    81→      if (packageJson.workspaces) {
    82→        return currentDir;
    83→      }
    84→    } catch {
    85→      // package.json not found or not readable, continue searching
    86→    }
    87→
    88→    // Move up one directory
    89→    currentDir = dirname(currentDir);
    90→  }
    91→
    92→  throw new Error('Could not find monorepo root (package.json with workspaces field)');
    93→}
    94→
    95→/**
    96→ * Display help message
    97→ */
    98→function displayHelp(): void {
    99→  console.log(`
   100→End-to-End Classification Pipeline Testing Tool
   101→
   102→Usage:
   103→  npm run test:pipeline -- --mode <mode> [options]
   104→
   105→Modes:
   106→  single       Process a single email by message ID
   107→  batch        Process multiple unclassified emails
   108→  date-range   Process emails within a date range
   109→  replay       Re-run full pipeline with session data (useful for configuration tuning)
   110→  replay-from  Replay pipeline from a specific stage using session data (advanced debugging)
   111→
   112→Options:
   113→  --mode <mode>           Required: single, batch, date-range, replay, or replay-from
   114→  --message-id <id>       Required for single mode: Gmail message ID
   115→  --limit <number>        Optional: Maximum emails to process (default: 10 for batch, 100 for date-range)
   116→  --start <YYYY-MM-DD>    Required for date-range: Start date
   117→  --end <YYYY-MM-DD>      Required for date-range: End date
   118→  --session-id <sessionId> Required for replay/replay-from modes: Session ID containing trace data
   119→  --replay-from <stage>   Required for replay-from mode: Stage to start from (e.g., ai-routing, rule-scoring)
   120→  --dry-run               Optional: Classify without persisting to database
   121→  --help                  Display this help message
   122→
   123→Examples:
   124→  # Single email
   125→  npm run test:pipeline -- --mode single --message-id 18f2a3b4c5d6e7f8
   126→
   127→  # Batch processing
   128→  npm run test:pipeline -- --mode batch --limit 10
   129→
   130→  # Date range
   131→  npm run test:pipeline -- --mode date-range --start 2025-09-01 --end 2025-09-30 --limit 50
   132→
   133→  # Dry run (no database writes)
   134→  npm run test:pipeline -- --mode batch --limit 5 --dry-run
   135→
   136→  # Full replay (re-run complete pipeline with session data)
   137→  npm run test:pipeline -- --mode replay --session-id 2025-10-04T10-30-45-123Z
   138→
   139→  # Advanced: Replay from AI routing stage (useful for tuning AI prompts)
   140→  npm run test:pipeline -- --mode replay-from --replay-from ai-routing --session-id 2025-10-04T10-30-45-123Z
   141→
   142→  # Advanced: Replay from rule scoring (useful for tuning scoring rules)
   143→  npm run test:pipeline -- --mode replay-from --replay-from rule-scoring --session-id 2025-10-04T10-30-45-123Z
   144→
   145→Output:
   146→  - Per-email results with labels, confidence, and processing time
   147→  - Summary statistics (total, success, errors, average time)
   148→  - Explainability traces in ./test-pipeline-results/<sessionId>/
   149→
   150→Configuration:
   151→  - Config files automatically located in repo root config/
   152→  - Database connection from environment variables
   153→  - Build classification-engine before first run: npm run build --workspace=packages/classification-engine
   154→`);
   155→}
   156→
   157→/**
   158→ * Parse command line arguments
   159→ *
   160→ * @param args - Process arguments (excluding node and script path)
   161→ * @returns Parsed CLI arguments
   162→ * @throws Error if required arguments missing or invalid
   163→ */
   164→export function parseArguments(args: string[]): CLIArguments {
   165→  // Check for help flag first
   166→  if (args.includes('--help') || args.includes('-h')) {
   167→    displayHelp();
   168→    process.exit(0);
   169→  }
   170→
   171→  const result: Partial<CLIArguments> = {
   172→    dryRun: false,
   173→  };
   174→
   175→  for (let i = 0; i < args.length; i++) {
   176→    const arg = args[i];
   177→
   178→    switch (arg) {
   179→      case '--mode':
   180→        if (i + 1 >= args.length) {
   181→          throw new Error('Missing value for --mode argument');
   182→        }
   183→        result.mode = args[++i] as 'single' | 'batch' | 'date-range' | 'replay' | 'replay-from';
   184→        break;
   185→      case '--message-id':
   186→        if (i + 1 >= args.length) {
   187→          throw new Error('Missing value for --message-id argument');
   188→        }
   189→        result.messageId = args[++i];
   190→        break;
   191→      case '--limit':
   192→        if (i + 1 >= args.length) {
   193→          throw new Error('Missing value for --limit argument');
   194→        }
   195→        result.limit = parseInt(args[++i], 10);
   196→        break;
   197→      case '--start':
   198→        if (i + 1 >= args.length) {
   199→          throw new Error('Missing value for --start argument');
   200→        }
   201→        result.startDate = args[++i];
   202→        break;
   203→      case '--end':
   204→        if (i + 1 >= args.length) {
   205→          throw new Error('Missing value for --end argument');
   206→        }
   207→        result.endDate = args[++i];
   208→        break;
   209→      case '--dry-run':
   210→        result.dryRun = true;
   211→        break;
   212→      case '--replay-from':
   213→        if (i + 1 >= args.length) {
   214→          throw new Error('Missing value for --replay-from argument');
   215→        }
   216→        result.replayFrom = args[++i];
   217→        break;
   218→      case '--session-id':
   219→        if (i + 1 >= args.length) {
   220→          throw new Error('Missing value for --session-id argument');
   221→        }
   222→        result.sessionId = args[++i];
   223→        break;
   224→    }
   225→  }
   226→
   227→  // Validate required arguments
   228→  if (!result.mode) {
   229→    throw new Error('Mode is required (--mode single|batch|date-range|replay|replay-from)');
   230→  }
   231→
   232→  if (!['single', 'batch', 'date-range', 'replay', 'replay-from'].includes(result.mode)) {
   233→    throw new Error('Invalid mode. Must be: single, batch, date-range, replay, or replay-from');
   234→  }
   235→
   236→  if (result.mode === 'single' && !result.messageId) {
   237→    throw new Error('message-id is required for single mode (--message-id <id>)');
   238→  }
   239→
   240→  if (result.mode === 'replay') {
   241→    if (!result.sessionId) {
   242→      throw new Error('--session-id <sessionId> is required for replay mode');
   243→    }
   244→  }
   245→
   246→  if (result.mode === 'replay-from') {
   247→    if (!result.replayFrom || !result.sessionId) {
   248→      throw new Error('Both --replay-from <stage> and --session-id <sessionId> are required for replay-from mode');
   249→    }
   250→  }
   251→
   252→  if (result.mode === 'date-range') {
   253→    if (!result.startDate || !result.endDate) {
   254→      throw new Error(
   255→        'Both start and end dates are required for date-range mode (--start YYYY-MM-DD --end YYYY-MM-DD)'
   256→      );
   257→    }
   258→  }
   259→
   260→  return result as CLIArguments;
   261→}
   262→
   263→/**
   264→ * Load configuration from config directory
   265→ *
   266→ * @returns Loaded category configuration
   267→ * @throws Error if configuration loading fails
   268→ */
   269→async function loadConfiguration(): Promise<CategoryConfiguration> {
   270→  // Find monorepo root to locate config directory
   271→  const repoRoot = await findRepoRoot();
   272→
   273→  const configLoader = new ConfigurationLoader({
   274→    configDir: join(repoRoot, 'config'),
   275→    enableHotReload: false,
   276→    validateOnLoad: true,
   277→  });
   278→
   279→  const categoryConfigResult = await configLoader.loadCategoryConfiguration();
   280→
   281→  if (!categoryConfigResult.validationPassed) {
   282→    throw new Error(`Configuration validation failed:\n${categoryConfigResult.validationErrors.join('\n')}`);
   283→  }
   284→
   285→  // Validate config exists before type assertion
   286→  if (!categoryConfigResult.config) {
   287→    throw new Error('Configuration loading returned empty config');
   288→  }
   289→
   290→  // Return full CategoryConfiguration
   291→  // Use safe type assertion pattern as config loader returns runtime-validated configuration
   292→  const config = categoryConfigResult.config as unknown as CategoryConfiguration;
   293→  if (!config.processingConfig) {
   294→    throw new Error('Missing processingConfig in category configuration');
   295→  }
   296→
   297→  return config;
   298→}
   299→
   300→/**
   301→ * Process single email through classification pipeline
   302→ *
   303→ * @param messageId - Gmail message ID
   304→ * @param config - Category configuration
   305→ * @param dryRun - If true, skip persistence
   306→ * @returns Processing summary
   307→ */
   308→export async function processSingleEmail(
   309→  messageId: string,
   310→  config: CategoryConfiguration,
   311→  dryRun: boolean
   312→): Promise<ProcessingSummary> {
   313→  const summary: ProcessingSummary = {
   314→    totalEmails: 1,
   315→    success: 0,
   316→    errors: 0,
   317→    totalDurationMs: 0,
   318→    errorDetails: [],
   319→  };
   320→
   321→  const startTime = Date.now();
   322→
   323→  try {
   324→    // 1. Fetch email from database
   325→    console.log(`Fetching email: ${messageId}`);
   326→    const email = await fetchEmailById(messageId);
   327→
   328→    // 2. Initialize pipeline with test mode enabled
   329→    const pipeline = new ClassificationPipeline(config, true);
   330→
   331→    // 3. Classify email
   332→    console.log(`Classifying: [${email.id}] ${email.subject}`);
   333→    const result = await pipeline.classify(email);
   334→
   335→    // 4. Output result
   336→    console.log(formatEmailOutput(email, result));
   337→
   338→    // 5. Persist result (unless dry-run)
   339→    if (!dryRun) {
   340→      await saveClassificationResult(messageId, result);
   341→      console.log(`Persisted classification result for ${messageId}`);
   342→    } else {
   343→      console.log(`[DRY RUN] Skipped persistence for ${messageId}`);
   344→    }
   345→
   346→    // 6. Write explainability trace
   347→    const tracePath = await writeExplainabilityTrace(email, result);
   348→    console.log(`Explainability trace: ${tracePath}`);
   349→
   350→    summary.success = 1;
   351→    summary.totalDurationMs = Date.now() - startTime;
   352→  } catch (error) {
   353→    summary.errors = 1;
   354→    summary.totalDurationMs = Date.now() - startTime;
   355→    summary.errorDetails.push({
   356→      messageId,
   357→      error: error instanceof Error ? error.message : String(error),
   358→    });
   359→
   360→    console.error(`Error processing ${messageId}: ${error instanceof Error ? error.message : String(error)}`);
   361→  }
   362→
   363→  return summary;
   364→}
   365→
   366→/**
   367→ * Process batch of unclassified emails
   368→ *
   369→ * @param limit - Maximum number of emails to process
   370→ * @param config - Category configuration
   371→ * @param dryRun - If true, skip persistence
   372→ * @returns Processing summary
   373→ */
   374→export async function processBatchEmails(
   375→  limit: number,
   376→  config: CategoryConfiguration,
   377→  dryRun: boolean
   378→): Promise<ProcessingSummary> {
   379→  const summary: ProcessingSummary = {
   380→    totalEmails: 0,
   381→    success: 0,
   382→    errors: 0,
   383→    totalDurationMs: 0,
   384→    errorDetails: [],
   385→  };
   386→
   387→  const startTime = Date.now();
   388→
   389→  try {
   390→    // 1. Fetch unclassified emails
   391→    console.log(`Fetching up to ${limit} unclassified emails...`);
   392→    const emails = await fetchUnclassifiedEmails(limit);
   393→
   394→    summary.totalEmails = emails.length;
   395→    console.log(`Found ${emails.length} emails to process\n`);
   396→
   397→    if (emails.length === 0) {
   398→      console.log('No unclassified emails found.');
   399→      summary.totalDurationMs = Date.now() - startTime;
   400→      return summary;
   401→    }
   402→
   403→    // 2. Initialize pipeline with test mode enabled
   404→    const pipeline = new ClassificationPipeline(config, true);
   405→
   406→    // 3. Process each email
   407→    for (const email of emails) {
   408→      try {
   409→        console.log(`Classifying [${email.id}] ${email.subject}`);
   410→        const result = await pipeline.classify(email);
   411→
   412→        console.log(formatEmailOutput(email, result));
   413→
   414→        if (!dryRun) {
   415→          await saveClassificationResult(email.id, result);
   416→        }
   417→
   418→        await writeExplainabilityTrace(email, result);
   419→
   420→        summary.success++;
   421→      } catch (error) {
   422→        summary.errors++;
   423→        summary.errorDetails.push({
   424→          messageId: email.id,
   425→          error: error instanceof Error ? error.message : String(error),
   426→        });
   427→
   428→        console.error(`Error processing ${email.id}: ${error instanceof Error ? error.message : String(error)}`);
   429→      }
   430→    }
   431→
   432→    summary.totalDurationMs = Date.now() - startTime;
   433→  } catch (error) {
   434→    console.error(`Fatal error in batch processing: ${error instanceof Error ? error.message : String(error)}`);
   435→    throw error;
   436→  }
   437→
   438→  return summary;
   439→}
   440→
   441→/**
   442→ * Process emails within date range
   443→ *
   444→ * @param startDate - Start date (YYYY-MM-DD)
   445→ * @param endDate - End date (YYYY-MM-DD)
   446→ * @param limit - Maximum number of emails to process
   447→ * @param config - Processing configuration
   448→ * @param dryRun - If true, skip persistence
   449→ * @returns Processing summary
   450→ */
   451→export async function processDateRangeEmails(
   452→  startDate: string,
   453→  endDate: string,
   454→  limit: number,
   455→  config: CategoryConfiguration,
   456→  dryRun: boolean
   457→): Promise<ProcessingSummary> {
   458→  const summary: ProcessingSummary = {
   459→    totalEmails: 0,
   460→    success: 0,
   461→    errors: 0,
   462→    totalDurationMs: 0,
   463→    errorDetails: [],
   464→  };
   465→
   466→  const startTime = Date.now();
   467→
   468→  try {
   469→    // Parse and validate dates
   470→    const start = new Date(startDate);
   471→    const end = new Date(endDate);
   472→
   473→    // Validate dates are valid
   474→    if (isNaN(start.getTime()) || isNaN(end.getTime())) {
   475→      throw new Error('Invalid date format. Use YYYY-MM-DD format for dates');
   476→    }
   477→
   478→    if (start > end) {
   479→      throw new Error('Invalid date range: start date must be before end date');
   480→    }
   481→
   482→    // 1. Fetch emails by date range
   483→    console.log(`Fetching emails from ${startDate} to ${endDate} (limit: ${limit})...`);
   484→    const emails = await fetchEmailsByDateRange(start, end, limit);
   485→
   486→    summary.totalEmails = emails.length;
   487→    console.log(`Found ${emails.length} emails to process\n`);
   488→
   489→    if (emails.length === 0) {
   490→      console.log('No emails found in date range.');
   491→      summary.totalDurationMs = Date.now() - startTime;
   492→      return summary;
   493→    }
   494→
   495→    // 2. Initialize pipeline with test mode enabled
   496→    const pipeline = new ClassificationPipeline(config, true);
   497→
   498→    // 3. Process each email
   499→    for (const email of emails) {
   500→      try {
   501→        console.log(`Classifying [${email.id}] ${email.subject}`);
   502→        const result = await pipeline.classify(email);
   503→
   504→        console.log(formatEmailOutput(email, result));
   505→
   506→        if (!dryRun) {
   507→          await saveClassificationResult(email.id, result);
   508→        }
   509→
   510→        await writeExplainabilityTrace(email, result);
   511→
   512→        summary.success++;
   513→      } catch (error) {
   514→        summary.errors++;
   515→        summary.errorDetails.push({
   516→          messageId: email.id,
   517→          error: error instanceof Error ? error.message : String(error),
   518→        });
   519→
   520→        console.error(`Error processing ${email.id}: ${error instanceof Error ? error.message : String(error)}`);
   521→      }
   522→    }
   523→
   524→    summary.totalDurationMs = Date.now() - startTime;
   525→  } catch (error) {
   526→    console.error(`Fatal error in date range processing: ${error instanceof Error ? error.message : String(error)}`);
   527→    throw error;
   528→  }
   529→
   530→  return summary;
   531→}
   532→
   533→/**
   534→ * Format per-email output line
   535→ *
   536→ * @param email - Email message
   537→ * @param result - Classification result
   538→ * @returns Formatted output string
   539→ */
   540→export function formatEmailOutput(email: EmailMessage, result: ClassificationResult): string {
   541→  const labels = result.selectedLabels.map((label: SelectedLabel) => label.subtype || label.category).join(', ');
   542→  const primaryLabel = result.selectedLabels.find((l: SelectedLabel) => l.isPrimary);
   543→  const confidence = primaryLabel ? primaryLabel.confidence.toFixed(2) : '0.00';
   544→  const durationSec = (result.processingDurationMs / 1000).toFixed(1);
   545→
   546→  return `[${email.id}] ${email.subject} → labels: [${labels || 'none'}] (confidence: ${confidence}) - ${durationSec}s`;
   547→}
   548→
   549→/**
   550→ * Format summary statistics
   551→ *
   552→ * @param summary - Processing summary
   553→ * @returns Formatted summary string
   554→ */
   555→export function formatSummary(summary: ProcessingSummary): string {
   556→  const totalSec = (summary.totalDurationMs / 1000).toFixed(1);
   557→  const avgSec = summary.totalEmails > 0 ? (summary.totalDurationMs / 1000 / summary.totalEmails).toFixed(2) : '0.00';
   558→
   559→  let output = `\n${'='.repeat(80)}\n`;
   560→  output += `Processed ${summary.totalEmails} emails in ${totalSec}s (avg ${avgSec}s/email)\n`;
   561→  output += `${summary.success} success, ${summary.errors} errors\n`;
   562→
   563→  if (summary.errorDetails.length > 0) {
   564→    output += '\nErrors:\n';
   565→    for (const error of summary.errorDetails) {
   566→      output += `  - [${error.messageId}] ${error.error}\n`;
   567→    }
   568→  }
   569→
   570→  output += `${'='.repeat(80)}\n`;
   571→
   572→  return output;
   573→}
   574→
   575→/**
   576→ * Write explainability trace to file
   577→ *
   578→ * @param email - Email message
   579→ * @param result - Classification result
   580→ * @returns Path to written trace file
   581→ */
   582→export async function writeExplainabilityTrace(email: EmailMessage, result: ClassificationResult): Promise<string> {
   583→  // Find monorepo root for consistent output location
   584→  const repoRoot = await findRepoRoot();
   585→
   586→  // Create sessionId-based output directory
   587→  const outputDir = join(repoRoot, 'test-pipeline-results', result.sessionId);
   588→
   589→  await fs.mkdir(outputDir, { recursive: true });
   590→
   591→  // Write trace JSON
   592→  const tracePath = join(outputDir, `${email.id}.json`);
   593→  const trace = {
   594→    messageId: email.id,
   595→    subject: email.subject,
   596→    from: email.from.email,
   597→    date: email.date,
   598→    classificationResult: result,
   599→    timestamp: new Date().toISOString(),
   600→  };
   601→
   602→  await fs.writeFile(tracePath, JSON.stringify(trace, null, 2));
   603→
   604→  return tracePath;
   605→}
   606→
   607→/**
   608→ * Pipeline stage mapping for replay functionality
   609→ */
   610→const STAGE_ORDER = [
   611→  'hard-assertions',
   612→  'strong-indicators',
   613→  'rule-scoring',
   614→  'attribute-detection',
   615→  'attribute-influence',
   616→  'disambiguation',
   617→  'multi-label-selection',
   618→  'ai-routing',
   619→  'ai-feature-extraction',
   620→  'ai-classification',
   621→  'ai-label-filtering',
   622→  'action-determination',
   623→] as const;
   624→
   625→type PipelineStage = (typeof STAGE_ORDER)[number];
   626→
   627→/**
   628→ * Load trace data from session directory and validate stage availability
   629→ *
   630→ * @param sessionId - Session ID to load traces from
   631→ * @param replayFromStage - Stage to start replay from
   632→ * @returns Array of trace data with email messages and classification results
   633→ */
   634→async function loadSessionTraces(
   635→  sessionId: string,
   636→  replayFromStage: PipelineStage
   637→): Promise<Array<{ email: EmailMessage; result: ClassificationResult; tracePath: string }>> {
   638→  const repoRoot = await findRepoRoot();
   639→  const sessionDir = join(repoRoot, 'test-pipeline-results', sessionId);
   640→
   641→  // Check if session directory exists
   642→  try {
   643→    await fs.access(sessionDir);
   644→  } catch {
   645→    throw new Error(`Session directory not found: ${sessionDir}. Please check the session ID.`);
   646→  }
   647→
   648→  // Get all trace files in the session
   649→  const files = await fs.readdir(sessionDir);
   650→  const traceFiles = files.filter((f) => f.endsWith('.json'));
   651→
   652→  if (traceFiles.length === 0) {
   653→    throw new Error(`No trace files found in session ${sessionId}`);
   654→  }
   655→
   656→  console.log(`Found ${traceFiles.length} trace files in session ${sessionId}`);
   657→
   658→  // Load and validate each trace
   659→  const traces: Array<{ email: EmailMessage; result: ClassificationResult; tracePath: string }> = [];
   660→
   661→  for (const file of traceFiles) {
   662→    const tracePath = join(sessionDir, file);
   663→
   664→    try {
   665→      const traceContent = await fs.readFile(tracePath, 'utf-8');
   666→      const trace = JSON.parse(traceContent);
   667→
   668→      if (!trace.classificationResult || !trace.messageId) {
   669→        console.warn(`Skipping invalid trace file: ${file}`);
   670→        continue;
   671→      }
   672→
   673→      // Validate that we have enough stage data to replay from the requested stage
   674→      const stageIndex = STAGE_ORDER.indexOf(replayFromStage);
   675→      if (stageIndex === -1) {
   676→        throw new Error(`Invalid stage: ${replayFromStage}. Valid stages: ${STAGE_ORDER.join(', ')}`);
   677→      }
   678→
   679→      // Check that all prior stages have been executed (basic validation)
   680→      const explainabilityTrace = trace.classificationResult.explainabilityTrace;
   681→      const requiredStages = STAGE_ORDER.slice(0, stageIndex);
   682→
   683→      for (const stage of requiredStages) {
   684→        // Map stage names to explainability trace properties
   685→        const hasStageData = getStageData(explainabilityTrace, stage);
   686→        if (!hasStageData) {
   687→          throw new Error(
   688→            `Missing required stage data for ${stage} in ${file}. Cannot replay from ${replayFromStage}.`
   689→          );
   690→        }
   691→      }
   692→
   693→      // Reconstruct email message from trace
   694→      const email: EmailMessage = {
   695→        id: trace.messageId,
   696→        threadId: '',
   697→        gmailLabels: [],
   698→        payload: {
   699→          mimeType: 'text/plain',
   700→          headers: [],
   701→          body: { data: '', size: 0 },
   702→        },
   703→        subject: trace.subject,
   704→        from: { email: trace.from, name: '', raw: trace.from },
   705→        to: [],
   706→        date: new Date(trace.date),
   707→        bodyPlain: trace.classificationResult.bodyContent || '',
   708→        isProcessed: false,
   709→        processingPriority: 0,
   710→      };
   711→
   712→      traces.push({
   713→        email,
   714→        result: trace.classificationResult,
   715→        tracePath,
   716→      });
   717→    } catch (error) {
   718→      console.warn(`Error loading trace file ${file}:`, error instanceof Error ? error.message : String(error));
   719→    }
