#!/usr/bin/env node
/**
 * End-to-End Testing CLI Tool (T036k)
 *
 * Simple CLI for manual end-to-end testing of classification pipeline.
 * Supports single email, batch, and date-range processing modes.
 *
 * Usage:
 *   npm run test:pipeline -- --mode single --message-id <id>
 *   npm run test:pipeline -- --mode batch --limit 10
 *   npm run test:pipeline -- --mode date-range --start 2025-09-01 --end 2025-09-30 --limit 50
 *   npm run test:pipeline -- --dry-run  # Classify without persisting
 *
 * Output:
 *   - Per-email: [message_id] subject → labels: [label1, label2] (confidence: 0.85) - 8.3s
 *   - Summary: Processed 10 emails in 83.5s (avg 8.35s/email), 9 success, 1 error
 *   - Explainability traces: ./test-pipeline-results/<timestamp>/<message_id>.json
 */

import { promises as fs } from 'fs';
import { join, dirname } from 'path';
import {
  fetchEmailById,
  fetchUnclassifiedEmails,
  fetchEmailsByDateRange,
  closePool as closeQueryPool,
} from '../persistence/email-query';
import { saveClassificationResult, closePool as closeWriterPool } from '../persistence/classification-writer';
import {
  ClassificationPipeline,
  ConfigurationLoader,
  type CategoryConfiguration,
  type EmailMessage,
  type ClassificationResult,
  type SelectedLabel,
} from '@gmail-automation/classification-engine';

/**
 * CLI argument structure
 */
export interface CLIArguments {
  mode: 'single' | 'batch' | 'date-range' | 'replay' | 'replay-from';
  messageId?: string;
  limit?: number;
  startDate?: string;
  endDate?: string;
  dryRun: boolean;
  replayFrom?: string;
  sessionId?: string;
}

/**
 * Processing summary statistics
 */
export interface ProcessingSummary {
  totalEmails: number;
  success: number;
  errors: number;
  totalDurationMs: number;
  errorDetails: Array<{ messageId: string; error: string }>;
}

/**
 * Find the monorepo root directory by searching upward for package.json with workspaces
 *
 * @param startDir - Directory to start searching from (defaults to current working directory)
 * @returns Path to monorepo root directory
 * @throws Error if monorepo root cannot be found
 */
export async function findRepoRoot(startDir: string = process.cwd()): Promise<string> {
  let currentDir = startDir;
  const root = '/';

  while (currentDir !== root) {
    try {
      const packageJsonPath = join(currentDir, 'package.json');
      const packageJsonContent = await fs.readFile(packageJsonPath, 'utf-8');
      const packageJson = JSON.parse(packageJsonContent);

      // Check if this package.json has workspaces field (indicates monorepo root)
      if (packageJson.workspaces) {
        return currentDir;
      }
    } catch {
      // package.json not found or not readable, continue searching
    }

    // Move up one directory
    currentDir = dirname(currentDir);
  }

  throw new Error('Could not find monorepo root (package.json with workspaces field)');
}

/**
 * Display help message
 */
function displayHelp(): void {
  console.log(`
End-to-End Classification Pipeline Testing Tool

Usage:
  npm run test:pipeline -- --mode <mode> [options]

Modes:
  single       Process a single email by message ID
  batch        Process multiple unclassified emails
  date-range   Process emails within a date range
  replay       Re-run full pipeline with session data (useful for configuration tuning)
  replay-from  Replay pipeline from a specific stage using session data (advanced debugging)

Options:
  --mode <mode>           Required: single, batch, date-range, replay, or replay-from
  --message-id <id>       Required for single mode: Gmail message ID
  --limit <number>        Optional: Maximum emails to process (default: 10 for batch, 100 for date-range)
  --start <YYYY-MM-DD>    Required for date-range: Start date
  --end <YYYY-MM-DD>      Required for date-range: End date
  --session-id <sessionId> Required for replay/replay-from modes: Session ID containing trace data
  --replay-from <stage>   Required for replay-from mode: Stage to start from (e.g., ai-routing, rule-scoring)
  --dry-run               Optional: Classify without persisting to database
  --help                  Display this help message

Examples:
  # Single email
  npm run test:pipeline -- --mode single --message-id 18f2a3b4c5d6e7f8

  # Batch processing
  npm run test:pipeline -- --mode batch --limit 10

  # Date range
  npm run test:pipeline -- --mode date-range --start 2025-09-01 --end 2025-09-30 --limit 50

  # Dry run (no database writes)
  npm run test:pipeline -- --mode batch --limit 5 --dry-run

  # Full replay (re-run complete pipeline with session data)
  npm run test:pipeline -- --mode replay --session-id 2025-10-04T10-30-45-123Z

  # Advanced: Replay from AI routing stage (useful for tuning AI prompts)
  npm run test:pipeline -- --mode replay-from --replay-from ai-routing --session-id 2025-10-04T10-30-45-123Z

  # Advanced: Replay from rule scoring (useful for tuning scoring rules)
  npm run test:pipeline -- --mode replay-from --replay-from rule-scoring --session-id 2025-10-04T10-30-45-123Z

Output:
  - Per-email results with labels, confidence, and processing time
  - Summary statistics (total, success, errors, average time)
  - Explainability traces in ./test-pipeline-results/<sessionId>/

Configuration:
  - Config files automatically located in repo root config/
  - Database connection from environment variables
  - Build classification-engine before first run: npm run build --workspace=packages/classification-engine
`);
}

/**
 * Parse command line arguments
 *
 * @param args - Process arguments (excluding node and script path)
 * @returns Parsed CLI arguments
 * @throws Error if required arguments missing or invalid
 */
export function parseArguments(args: string[]): CLIArguments {
  // Check for help flag first
  if (args.includes('--help') || args.includes('-h')) {
    displayHelp();
    process.exit(0);
  }

  const result: Partial<CLIArguments> = {
    dryRun: false,
  };

  for (let i = 0; i < args.length; i++) {
    const arg = args[i];

    switch (arg) {
      case '--mode':
        if (i + 1 >= args.length) {
          throw new Error('Missing value for --mode argument');
        }
        result.mode = args[++i] as 'single' | 'batch' | 'date-range' | 'replay' | 'replay-from';
        break;
      case '--message-id':
        if (i + 1 >= args.length) {
          throw new Error('Missing value for --message-id argument');
        }
        result.messageId = args[++i];
        break;
      case '--limit':
        if (i + 1 >= args.length) {
          throw new Error('Missing value for --limit argument');
        }
        result.limit = parseInt(args[++i], 10);
        break;
      case '--start':
        if (i + 1 >= args.length) {
          throw new Error('Missing value for --start argument');
        }
        result.startDate = args[++i];
        break;
      case '--end':
        if (i + 1 >= args.length) {
          throw new Error('Missing value for --end argument');
        }
        result.endDate = args[++i];
        break;
      case '--dry-run':
        result.dryRun = true;
        break;
      case '--replay-from':
        if (i + 1 >= args.length) {
          throw new Error('Missing value for --replay-from argument');
        }
        result.replayFrom = args[++i];
        break;
      case '--session-id':
        if (i + 1 >= args.length) {
          throw new Error('Missing value for --session-id argument');
        }
        result.sessionId = args[++i];
        break;
    }
  }

  // Validate required arguments
  if (!result.mode) {
    throw new Error('Mode is required (--mode single|batch|date-range|replay|replay-from)');
  }

  if (!['single', 'batch', 'date-range', 'replay', 'replay-from'].includes(result.mode)) {
    throw new Error('Invalid mode. Must be: single, batch, date-range, replay, or replay-from');
  }

  if (result.mode === 'single' && !result.messageId) {
    throw new Error('message-id is required for single mode (--message-id <id>)');
  }

  if (result.mode === 'replay') {
    if (!result.sessionId) {
      throw new Error('--session-id <sessionId> is required for replay mode');
    }
  }

  if (result.mode === 'replay-from') {
    if (!result.replayFrom || !result.sessionId) {
      throw new Error('Both --replay-from <stage> and --session-id <sessionId> are required for replay-from mode');
    }
  }

  if (result.mode === 'date-range') {
    if (!result.startDate || !result.endDate) {
      throw new Error(
        'Both start and end dates are required for date-range mode (--start YYYY-MM-DD --end YYYY-MM-DD)'
      );
    }
  }

  return result as CLIArguments;
}

/**
 * Load configuration from config directory
 *
 * @returns Loaded category configuration
 * @throws Error if configuration loading fails
 */
async function loadConfiguration(): Promise<CategoryConfiguration> {
  // Find monorepo root to locate config directory
  const repoRoot = await findRepoRoot();

  const configLoader = new ConfigurationLoader({
    configDir: join(repoRoot, 'config'),
    enableHotReload: false,
    validateOnLoad: true,
  });

  const categoryConfigResult = await configLoader.loadCategoryConfiguration();

  if (!categoryConfigResult.validationPassed) {
    throw new Error(`Configuration validation failed:\n${categoryConfigResult.validationErrors.join('\n')}`);
  }

  // Validate config exists before type assertion
  if (!categoryConfigResult.config) {
    throw new Error('Configuration loading returned empty config');
  }

  // Return full CategoryConfiguration
  // Use safe type assertion pattern as config loader returns runtime-validated configuration
  const config = categoryConfigResult.config as unknown as CategoryConfiguration;
  if (!config.processingConfig) {
    throw new Error('Missing processingConfig in category configuration');
  }

  return config;
}

/**
 * Process single email through classification pipeline
 *
 * @param messageId - Gmail message ID
 * @param config - Category configuration
 * @param dryRun - If true, skip persistence
 * @returns Processing summary
 */
export async function processSingleEmail(
  messageId: string,
  config: CategoryConfiguration,
  dryRun: boolean
): Promise<ProcessingSummary> {
  const summary: ProcessingSummary = {
    totalEmails: 1,
    success: 0,
    errors: 0,
    totalDurationMs: 0,
    errorDetails: [],
  };

  const startTime = Date.now();

  try {
    // 1. Fetch email from database
    console.log(`Fetching email: ${messageId}`);
    const email = await fetchEmailById(messageId);

    // 2. Initialize pipeline with test mode enabled
    const pipeline = new ClassificationPipeline(config, true);

    // 3. Classify email
    console.log(`Classifying: [${email.id}] ${email.subject}`);
    const result = await pipeline.classify(email);

    // 4. Output result
    console.log(formatEmailOutput(email, result));

    // 5. Persist result (unless dry-run)
    if (!dryRun) {
      await saveClassificationResult(messageId, result);
      console.log(`Persisted classification result for ${messageId}`);
    } else {
      console.log(`[DRY RUN] Skipped persistence for ${messageId}`);
    }

    // 6. Write explainability trace
    const tracePath = await writeExplainabilityTrace(email, result);
    console.log(`Explainability trace: ${tracePath}`);

    summary.success = 1;
    summary.totalDurationMs = Date.now() - startTime;
  } catch (error) {
    summary.errors = 1;
    summary.totalDurationMs = Date.now() - startTime;
    summary.errorDetails.push({
      messageId,
      error: error instanceof Error ? error.message : String(error),
    });

    console.error(`Error processing ${messageId}: ${error instanceof Error ? error.message : String(error)}`);
  }

  return summary;
}

/**
 * Process batch of unclassified emails
 *
 * @param limit - Maximum number of emails to process
 * @param config - Category configuration
 * @param dryRun - If true, skip persistence
 * @returns Processing summary
 */
export async function processBatchEmails(
  limit: number,
  config: CategoryConfiguration,
  dryRun: boolean
): Promise<ProcessingSummary> {
  const summary: ProcessingSummary = {
    totalEmails: 0,
    success: 0,
    errors: 0,
    totalDurationMs: 0,
    errorDetails: [],
  };

  const startTime = Date.now();

  try {
    // 1. Fetch unclassified emails
    console.log(`Fetching up to ${limit} unclassified emails...`);
    const emails = await fetchUnclassifiedEmails(limit);

    summary.totalEmails = emails.length;
    console.log(`Found ${emails.length} emails to process\n`);

    if (emails.length === 0) {
      console.log('No unclassified emails found.');
      summary.totalDurationMs = Date.now() - startTime;
      return summary;
    }

    // 2. Initialize pipeline with test mode enabled
    const pipeline = new ClassificationPipeline(config, true);

    // 3. Create single session for entire batch
    const {
      createClassificationSession,
      incrementSessionSuccess,
      incrementSessionError,
      finalizeClassificationSession,
    } = await import('@gmail-automation/classification-engine');
    const session = createClassificationSession(config.processingConfig, 'sequential', emails.length, true);

    // 4. Process each email with shared session
    for (let i = 0; i < emails.length; i++) {
      const email = emails[i];
      try {
        console.log(`Classifying [${email.id}] ${email.subject}`);
        const result = await pipeline.classifyWithSession(email, session, i);

        console.log(formatEmailOutput(email, result));

        if (!dryRun) {
          await saveClassificationResult(email.id, result);
        }

        await writeExplainabilityTrace(email, result);

        incrementSessionSuccess(session);
        summary.success++;
      } catch (error) {
        incrementSessionError(session);
        summary.errors++;
        summary.errorDetails.push({
          messageId: email.id,
          error: error instanceof Error ? error.message : String(error),
        });

        console.error(`Error processing ${email.id}: ${error instanceof Error ? error.message : String(error)}`);
      }
    }

    // 5. Finalize session
    finalizeClassificationSession(session);

    summary.totalDurationMs = Date.now() - startTime;
  } catch (error) {
    console.error(`Fatal error in batch processing: ${error instanceof Error ? error.message : String(error)}`);
    throw error;
  }

  return summary;
}

/**
 * Process emails within date range
 *
 * @param startDate - Start date (YYYY-MM-DD)
 * @param endDate - End date (YYYY-MM-DD)
 * @param limit - Maximum number of emails to process
 * @param config - Processing configuration
 * @param dryRun - If true, skip persistence
 * @returns Processing summary
 */
export async function processDateRangeEmails(
  startDate: string,
  endDate: string,
  limit: number,
  config: CategoryConfiguration,
  dryRun: boolean
): Promise<ProcessingSummary> {
  const summary: ProcessingSummary = {
    totalEmails: 0,
    success: 0,
    errors: 0,
    totalDurationMs: 0,
    errorDetails: [],
  };

  const startTime = Date.now();

  try {
    // Parse and validate dates
    const start = new Date(startDate);
    const end = new Date(endDate);

    // Validate dates are valid
    if (isNaN(start.getTime()) || isNaN(end.getTime())) {
      throw new Error('Invalid date format. Use YYYY-MM-DD format for dates');
    }

    if (start > end) {
      throw new Error('Invalid date range: start date must be before end date');
    }

    // 1. Fetch emails by date range
    console.log(`Fetching emails from ${startDate} to ${endDate} (limit: ${limit})...`);
    const emails = await fetchEmailsByDateRange(start, end, limit);

    summary.totalEmails = emails.length;
    console.log(`Found ${emails.length} emails to process\n`);

    if (emails.length === 0) {
      console.log('No emails found in date range.');
      summary.totalDurationMs = Date.now() - startTime;
      return summary;
    }

    // 2. Initialize pipeline with test mode enabled
    const pipeline = new ClassificationPipeline(config, true);

    // 3. Process each email
    for (const email of emails) {
      try {
        console.log(`Classifying [${email.id}] ${email.subject}`);
        const result = await pipeline.classify(email);

        console.log(formatEmailOutput(email, result));

        if (!dryRun) {
          await saveClassificationResult(email.id, result);
        }

        await writeExplainabilityTrace(email, result);

        summary.success++;
      } catch (error) {
        summary.errors++;
        summary.errorDetails.push({
          messageId: email.id,
          error: error instanceof Error ? error.message : String(error),
        });

        console.error(`Error processing ${email.id}: ${error instanceof Error ? error.message : String(error)}`);
      }
    }

    summary.totalDurationMs = Date.now() - startTime;
  } catch (error) {
    console.error(`Fatal error in date range processing: ${error instanceof Error ? error.message : String(error)}`);
    throw error;
  }

  return summary;
}

/**
 * Format per-email output line
 *
 * @param email - Email message
 * @param result - Classification result
 * @returns Formatted output string
 */
export function formatEmailOutput(email: EmailMessage, result: ClassificationResult): string {
  const labels = result.selectedLabels.map((label: SelectedLabel) => label.subtype || label.category).join(', ');
  const primaryLabel = result.selectedLabels.find((l: SelectedLabel) => l.isPrimary);
  const confidence = primaryLabel ? primaryLabel.confidence.toFixed(2) : '0.00';
  const durationSec = (result.processingDurationMs / 1000).toFixed(1);

  return `[${email.id}] ${email.subject} → labels: [${labels || 'none'}] (confidence: ${confidence}) - ${durationSec}s`;
}

/**
 * Format summary statistics
 *
 * @param summary - Processing summary
 * @returns Formatted summary string
 */
export function formatSummary(summary: ProcessingSummary): string {
  const totalSec = (summary.totalDurationMs / 1000).toFixed(1);
  const avgSec = summary.totalEmails > 0 ? (summary.totalDurationMs / 1000 / summary.totalEmails).toFixed(2) : '0.00';

  let output = `\n${'='.repeat(80)}\n`;
  output += `Processed ${summary.totalEmails} emails in ${totalSec}s (avg ${avgSec}s/email)\n`;
  output += `${summary.success} success, ${summary.errors} errors\n`;

  if (summary.errorDetails.length > 0) {
    output += '\nErrors:\n';
    for (const error of summary.errorDetails) {
      output += `  - [${error.messageId}] ${error.error}\n`;
    }
  }

  output += `${'='.repeat(80)}\n`;

  return output;
}

/**
 * Write explainability trace to file
 *
 * @param email - Email message
 * @param result - Classification result
 * @returns Path to written trace file
 */
export async function writeExplainabilityTrace(email: EmailMessage, result: ClassificationResult): Promise<string> {
  // Find monorepo root for consistent output location
  const repoRoot = await findRepoRoot();

  // Create sessionId-based output directory
  const outputDir = join(repoRoot, 'test-pipeline-results', result.sessionId);

  await fs.mkdir(outputDir, { recursive: true });

  // Write trace JSON
  const tracePath = join(outputDir, `${email.id}.json`);
  const trace = {
    messageId: email.id,
    subject: email.subject,
    from: email.from.email,
    date: email.date,
    classificationResult: result,
    timestamp: new Date().toISOString(),
  };

  await fs.writeFile(tracePath, JSON.stringify(trace, null, 2));

  return tracePath;
}

/**
 * Pipeline stage mapping for replay functionality
 */
const STAGE_ORDER = [
  'hard-assertions',
  'strong-indicators',
  'rule-scoring',
  'attribute-detection',
  'attribute-influence',
  'disambiguation',
  'multi-label-selection',
  'ai-routing',
  'ai-feature-extraction',
  'ai-classification',
  'ai-label-filtering',
  'action-determination',
] as const;

type PipelineStage = (typeof STAGE_ORDER)[number];

/**
 * Load trace data from session directory and validate stage availability
 *
 * @param sessionId - Session ID to load traces from
 * @param replayFromStage - Stage to start replay from
 * @returns Array of trace data with email messages and classification results
 */
async function loadSessionTraces(
  sessionId: string,
  replayFromStage: PipelineStage
): Promise<Array<{ email: EmailMessage; result: ClassificationResult; tracePath: string }>> {
  const repoRoot = await findRepoRoot();
  const sessionDir = join(repoRoot, 'test-pipeline-results', sessionId);

  // Check if session directory exists
  try {
    await fs.access(sessionDir);
  } catch {
    throw new Error(`Session directory not found: ${sessionDir}. Please check the session ID.`);
  }

  // Get all trace files in the session
  const files = await fs.readdir(sessionDir);
  const traceFiles = files.filter((f) => f.endsWith('.json'));

  if (traceFiles.length === 0) {
    throw new Error(`No trace files found in session ${sessionId}`);
  }

  console.log(`Found ${traceFiles.length} trace files in session ${sessionId}`);

  // Load and validate each trace
  const traces: Array<{ email: EmailMessage; result: ClassificationResult; tracePath: string }> = [];

  for (const file of traceFiles) {
    const tracePath = join(sessionDir, file);

    try {
      const traceContent = await fs.readFile(tracePath, 'utf-8');
      const trace = JSON.parse(traceContent);

      if (!trace.classificationResult || !trace.messageId) {
        console.warn(`Skipping invalid trace file: ${file}`);
        continue;
      }

      // Validate that we have enough stage data to replay from the requested stage
      const stageIndex = STAGE_ORDER.indexOf(replayFromStage);
      if (stageIndex === -1) {
        throw new Error(`Invalid stage: ${replayFromStage}. Valid stages: ${STAGE_ORDER.join(', ')}`);
      }

      // Check that all prior stages have been executed (basic validation)
      const explainabilityTrace = trace.classificationResult.explainabilityTrace;
      const requiredStages = STAGE_ORDER.slice(0, stageIndex);

      for (const stage of requiredStages) {
        // Map stage names to explainability trace properties
        const hasStageData = getStageData(explainabilityTrace, stage);
        if (!hasStageData) {
          throw new Error(
            `Missing required stage data for ${stage} in ${file}. Cannot replay from ${replayFromStage}.`
          );
        }
      }

      // Reconstruct email message from trace
      const email: EmailMessage = {
        id: trace.messageId,
        threadId: '',
        gmailLabels: [],
        payload: {
          mimeType: 'text/plain',
          headers: [],
          body: { data: '', size: 0 },
        },
        subject: trace.subject,
        from: { email: trace.from, name: '', raw: trace.from },
        to: [],
        date: new Date(trace.date),
        bodyPlain: trace.classificationResult.bodyContent || '',
        isProcessed: false,
        processingPriority: 0,
      };

      traces.push({
        email,
        result: trace.classificationResult,
        tracePath,
      });
    } catch (error) {
      console.warn(`Error loading trace file ${file}:`, error instanceof Error ? error.message : String(error));
    }
  }

  if (traces.length === 0) {
    throw new Error(`No valid trace files found in session ${sessionId}`);
  }

  console.log(`Successfully loaded ${traces.length} valid traces for replay from ${replayFromStage}`);
  return traces;
}

/**
 * Check if stage data exists in explainability trace
 */
function getStageData(trace: unknown, stage: PipelineStage): boolean {
  const traceObj = trace as Record<string, unknown>;
  switch (stage) {
    case 'hard-assertions':
      return Array.isArray(traceObj.hardAssertions) && (traceObj.hardAssertions as unknown[]).length >= 0;
    case 'strong-indicators':
      return Array.isArray(traceObj.strongIndicators) && (traceObj.strongIndicators as unknown[]).length >= 0;
    case 'rule-scoring':
      return Array.isArray(traceObj.ruleScoring) && (traceObj.ruleScoring as unknown[]).length >= 0;
    case 'attribute-detection':
      return Array.isArray(traceObj.attributeDetection) && (traceObj.attributeDetection as unknown[]).length >= 0;
    case 'attribute-influence':
      return Array.isArray(traceObj.attributeInfluence) && (traceObj.attributeInfluence as unknown[]).length >= 0;
    case 'disambiguation':
      return Array.isArray(traceObj.disambiguation) && (traceObj.disambiguation as unknown[]).length >= 0;
    case 'multi-label-selection':
      return Array.isArray(traceObj.multiLabelSelection) && (traceObj.multiLabelSelection as unknown[]).length >= 0;
    case 'ai-routing':
      return traceObj.aiRouting !== undefined;
    case 'ai-feature-extraction':
    case 'ai-classification':
    case 'ai-label-filtering':
    case 'action-determination':
      return true; // These stages can always be replayed
    default:
      return false;
  }
}

/**
 * Process emails using simple replay mode - re-run full pipeline with session data
 *
 * @param sessionId - Session ID containing trace data
 * @param config - Category configuration
 * @param dryRun - If true, skip persistence
 * @returns Processing summary
 */
export async function processFullReplay(
  sessionId: string,
  config: CategoryConfiguration,
  dryRun: boolean
): Promise<ProcessingSummary> {
  const summary: ProcessingSummary = {
    totalEmails: 0,
    success: 0,
    errors: 0,
    totalDurationMs: 0,
    errorDetails: [],
  };

  const startTime = Date.now();

  try {
    console.log(`Full replay mode: Re-running complete pipeline using session ${sessionId}`);

    // Load session traces (we can reuse the same function, just ignore stage validation)
    const traces = await loadSessionTracesSimple(sessionId);
    summary.totalEmails = traces.length;

    console.log(`Re-running full pipeline for configuration tuning and comparison\n`);

    // Initialize pipeline with test mode
    const pipeline = new ClassificationPipeline(config, true);

    // Process each email from the loaded traces
    for (const { email } of traces) {
      try {
        console.log(`Replaying [${email.id}] ${email.subject}`);

        // Re-run classification (full pipeline)
        const newResult = await pipeline.classify(email);

        console.log(formatEmailOutput(email, newResult));

        // Persist result (unless dry-run)
        if (!dryRun) {
          await saveClassificationResult(email.id, newResult);
        }

        // Write new explainability trace (will use new sessionId)
        await writeExplainabilityTrace(email, newResult);

        summary.success++;
      } catch (error) {
        summary.errors++;
        summary.errorDetails.push({
          messageId: email.id,
          error: error instanceof Error ? error.message : String(error),
        });

        console.error(`Error replaying ${email.id}: ${error instanceof Error ? error.message : String(error)}`);
      }
    }

    summary.totalDurationMs = Date.now() - startTime;
  } catch (error) {
    console.error(`Fatal error in full replay mode: ${error instanceof Error ? error.message : String(error)}`);
    throw error;
  }

  return summary;
}

/**
 * Load trace data from session directory (simplified version for full replay)
 *
 * @param sessionId - Session ID to load traces from
 * @returns Array of trace data with email messages and classification results
 */
async function loadSessionTracesSimple(
  sessionId: string
): Promise<Array<{ email: EmailMessage; result: ClassificationResult; tracePath: string }>> {
  const repoRoot = await findRepoRoot();
  const sessionDir = join(repoRoot, 'test-pipeline-results', sessionId);

  // Check if session directory exists
  try {
    await fs.access(sessionDir);
  } catch {
    throw new Error(`Session directory not found: ${sessionDir}. Please check the session ID.`);
  }

  // Get all trace files in the session
  const files = await fs.readdir(sessionDir);
  const traceFiles = files.filter((f) => f.endsWith('.json'));

  if (traceFiles.length === 0) {
    throw new Error(`No trace files found in session ${sessionId}`);
  }

  console.log(`Found ${traceFiles.length} trace files in session ${sessionId}`);

  // Load each trace
  const traces: Array<{ email: EmailMessage; result: ClassificationResult; tracePath: string }> = [];

  for (const file of traceFiles) {
    const tracePath = join(sessionDir, file);

    try {
      const traceContent = await fs.readFile(tracePath, 'utf-8');
      const trace = JSON.parse(traceContent);

      if (!trace.classificationResult || !trace.messageId) {
        console.warn(`Skipping invalid trace file: ${file}`);
        continue;
      }

      // Reconstruct email message from trace
      const email: EmailMessage = {
        id: trace.messageId,
        threadId: '',
        gmailLabels: [],
        payload: {
          mimeType: 'text/plain',
          headers: [],
          body: { data: '', size: 0 },
        },
        subject: trace.subject,
        from: { email: trace.from, name: '', raw: trace.from },
        to: [],
        date: new Date(trace.date),
        bodyPlain: trace.classificationResult.bodyContent || '',
        isProcessed: false,
        processingPriority: 0,
      };

      traces.push({
        email,
        result: trace.classificationResult,
        tracePath,
      });
    } catch (error) {
      console.warn(`Error loading trace file ${file}:`, error instanceof Error ? error.message : String(error));
    }
  }

  if (traces.length === 0) {
    throw new Error(`No valid trace files found in session ${sessionId}`);
  }

  console.log(`Successfully loaded ${traces.length} traces for full replay`);
  return traces;
}

/**
 * Process emails using replay-from mode - load state and continue from specified stage
 *
 * @param replayFromStage - Stage to start replay from
 * @param sessionId - Session ID containing trace data
 * @param config - Category configuration
 * @param dryRun - If true, skip persistence
 * @returns Processing summary
 */
export async function processReplayFromMode(
  replayFromStage: string,
  sessionId: string,
  config: CategoryConfiguration,
  dryRun: boolean
): Promise<ProcessingSummary> {
  const summary: ProcessingSummary = {
    totalEmails: 0,
    success: 0,
    errors: 0,
    totalDurationMs: 0,
    errorDetails: [],
  };

  const startTime = Date.now();

  try {
    console.log(`Replay mode: Starting from ${replayFromStage} using session ${sessionId}`);

    // Load and validate session traces
    const traces = await loadSessionTraces(sessionId, replayFromStage as PipelineStage);
    summary.totalEmails = traces.length;

    console.log(`\nUsing StageTask architecture for true stage-by-stage replay starting from: ${replayFromStage}\n`);

    // Initialize pipeline with test mode
    const pipeline = new ClassificationPipeline(config, true);

    // Process each email from the loaded traces
    for (const { email } of traces) {
      try {
        console.log(`Replaying [${email.id}] ${email.subject}`);

        // Re-run classification using StageTask architecture for true replay-from-stage support
        const newResult = await pipeline.classifyWithStageTask(email, replayFromStage);

        console.log(formatEmailOutput(email, newResult));

        // Persist result (unless dry-run)
        if (!dryRun) {
          await saveClassificationResult(email.id, newResult);
        }

        // Write new explainability trace (will use new sessionId)
        await writeExplainabilityTrace(email, newResult);

        summary.success++;
      } catch (error) {
        summary.errors++;
        summary.errorDetails.push({
          messageId: email.id,
          error: error instanceof Error ? error.message : String(error),
        });

        console.error(`Error replaying ${email.id}: ${error instanceof Error ? error.message : String(error)}`);
      }
    }

    summary.totalDurationMs = Date.now() - startTime;
  } catch (error) {
    console.error(`Fatal error in replay mode: ${error instanceof Error ? error.message : String(error)}`);
    throw error;
  }

  return summary;
}

/**
 * Main CLI entry point
 *
 * @param args - Command line arguments
 * @returns Exit code (0 = success, 1 = error)
 */
export async function runTestPipeline(args: string[]): Promise<number> {
  try {
    // 1. Parse arguments
    const cliArgs = parseArguments(args);

    console.log(`\nTest Pipeline - Mode: ${cliArgs.mode}${cliArgs.dryRun ? ' [DRY RUN]' : ''}\n`);

    // 2. Load configuration
    console.log('Loading configuration...');
    const config = await loadConfiguration();
    console.log('Configuration loaded successfully\n');

    // 3. Process based on mode
    let summary: ProcessingSummary;

    switch (cliArgs.mode) {
      case 'single':
        summary = await processSingleEmail(cliArgs.messageId!, config, cliArgs.dryRun);
        break;

      case 'batch':
        summary = await processBatchEmails(cliArgs.limit || 10, config, cliArgs.dryRun);
        break;

      case 'date-range':
        summary = await processDateRangeEmails(
          cliArgs.startDate!,
          cliArgs.endDate!,
          cliArgs.limit || 100,
          config,
          cliArgs.dryRun
        );
        break;

      case 'replay':
        summary = await processFullReplay(cliArgs.sessionId!, config, cliArgs.dryRun);
        break;

      case 'replay-from':
        summary = await processReplayFromMode(cliArgs.replayFrom!, cliArgs.sessionId!, config, cliArgs.dryRun);
        break;
    }

    // 4. Print summary
    console.log(formatSummary(summary));

    // 5. Cleanup
    await closeQueryPool();
    await closeWriterPool();

    // 6. Return exit code
    return summary.errors > 0 ? 1 : 0;
  } catch (error) {
    console.error(`\nFatal error: ${error instanceof Error ? error.message : String(error)}`);

    // Cleanup on error
    try {
      await closeQueryPool();
      await closeWriterPool();
    } catch {
      // Ignore cleanup errors
    }

    return 1;
  }
}

/**
 * CLI execution (only when run directly)
 */
if (require.main === module) {
  runTestPipeline(process.argv.slice(2))
    .then((exitCode) => {
      process.exit(exitCode);
    })
    .catch((error) => {
      console.error('Unexpected error:', error);
      process.exit(1);
    });
}

