/**
 * Dual-Output Logger
 *
 * Provides logging that outputs to both console and a file simultaneously.
 * Used by test-pipeline CLI to create per-email log files while maintaining
 * console output for real-time monitoring.
 */

import { promises as fs } from 'fs';
import { join } from 'path';

/**
 * Logger interface for dual output (console + file)
 */
export interface DualLogger {
  log: (message: string) => void;
  error: (message: string) => void;
  warn: (message: string) => void;
  flush: () => Promise<void>;
  close: () => Promise<void>;
}

/**
 * Create a dual-output logger that writes to both console and file
 *
 * @param logFilePath - Absolute path to log file
 * @param enableConsole - Whether to also output to console (default: true)
 * @returns DualLogger instance
 */
export async function createDualLogger(logFilePath: string, enableConsole: boolean = true): Promise<DualLogger> {
  const logBuffer: string[] = [];
  let fileHandle: fs.FileHandle | null = null;

  // Ensure directory exists
  const logDir = join(logFilePath, '..');
  await fs.mkdir(logDir, { recursive: true });

  // Open file for writing
  fileHandle = await fs.open(logFilePath, 'w');

  /**
   * Write message to both console and file
   */
  const writeMessage = (level: string, message: string): void => {
    const timestamp = new Date().toISOString();
    const logLine = `[${timestamp}] [${level}] ${message}`;

    // Output to console
    if (enableConsole) {
      if (level === 'ERROR') {
        console.error(message);
      } else if (level === 'WARN') {
        console.warn(message);
      } else {
        console.log(message);
      }
    }

    // Buffer for file writing
    logBuffer.push(logLine + '\n');
  };

  /**
   * Flush buffered logs to file
   */
  const flush = async (): Promise<void> => {
    if (fileHandle && logBuffer.length > 0) {
      const content = logBuffer.join('');
      await fileHandle.write(content);
      logBuffer.length = 0; // Clear buffer
    }
  };

  /**
   * Close file handle and flush remaining logs
   */
  const close = async (): Promise<void> => {
    await flush();
    if (fileHandle) {
      await fileHandle.close();
      fileHandle = null;
    }
  };

  return {
    log: (message: string) => writeMessage('INFO', message),
    error: (message: string) => writeMessage('ERROR', message),
    warn: (message: string) => writeMessage('WARN', message),
    flush,
    close,
  };
}

/**
 * No-op logger that does nothing (useful for disabling logging)
 */
export const noopLogger: DualLogger = {
  log: () => {},
  error: () => {},
  warn: () => {},
  flush: async () => {},
  close: async () => {},
};

