/**
 * Classification Pipeline Error
 *
 * Custom error class that includes partial classification result when a pipeline stage fails.
 * This allows debugging and analysis of what was completed before the failure.
 */

import type { ClassificationResult } from './classification-result';

/**
 * Error thrown during classification pipeline execution
 *
 * Includes the partial classification result that was built up until the failure point.
 * This enables debugging by showing exactly what stages completed successfully and
 * what state the classification was in when it failed.
 */
export class ClassificationPipelineError extends Error {
  /**
   * Partial classification result up to the point of failure
   *
   * Contains all scores, labels, and explainability data from stages that
   * completed successfully before the error occurred.
   */
  public readonly partialResult: ClassificationResult;

  /**
   * Email ID that failed classification
   */
  public readonly emailId: string;

  /**
   * Stage name where the error occurred
   */
  public readonly stage: string;

  /**
   * Original error that caused the failure
   */
  public readonly cause?: Error;

  constructor(
    message: string,
    emailId: string,
    stage: string,
    partialResult: ClassificationResult,
    cause?: Error
  ) {
    super(message);
    this.name = 'ClassificationPipelineError';
    this.emailId = emailId;
    this.stage = stage;
    this.partialResult = partialResult;
    this.cause = cause;

    // Maintain proper stack trace for where error was thrown (only available on V8)
    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, ClassificationPipelineError);
    }
  }
}

